import logo from './logo.svg';
import './App.css';
import "react-widgets/styles.css";
import { Combobox } from 'react-widgets'; 
import React, { useState } from 'react';
import BeatenGameList from './Component/BeatenGameList';

// workaround meanwhile is fetching data
let keys = ["2023","2022","2021","2020"]


function initComboBox(keyslist)
{
  
  keys=(keyslist).reverse()
}

function App() {
  var resizeTimer;

  const [year, setYear] = useState(2023);
  const [rows, setRows] = useState(4);

  window.addEventListener('resize', function(){
    clearTimeout(resizeTimer);
    resizeTimer = setTimeout(resizeRows, 100);
}, true);

    function resizeRows()
    {
     if ( rows != 1 && visualViewport.width <= 500) {setRows(1);} // Mobile
     if ( rows != 2 && visualViewport.width > 500 && visualViewport.width <= 810) {setRows(2)} // Tablet-like
     if (rows != 3 && visualViewport.width > 811 && visualViewport.width <= 1128 ) {setRows(3)} // Tablet-like
     if (visualViewport.width > 1128 && rows != 4){setRows(4)}
    }

    resizeRows();

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <Combobox name="fieldyear" className="Combobox"  defaultValue="2023" data={keys} onChange={(year) => (setYear(year))}></Combobox>
        <BeatenGameList yearToList={year} rows={rows} callback={initComboBox} />
      </header>
    </div>
  );
}

export default App;
